parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const resume_id = body.resume_id;
const message = body.message;

if (!resume_id) throw new Error('resume_id obrigatório no body.');
if (!message || message.trim() === '') throw new Error('message não pode ser vazio.');

return [{ json: { resume_id, message } }];

const row = $input.first().json;
const body = $('Code - Valida Body').first().json;

if (!row || !row.resume_id) {
  throw new Error('Resume não encontrado para id: ' + body.resume_id);
}

return [{
  json: {
    resume_id:           body.resume_id,
    message:             body.message,
    employability_score: row.employability_score ?? '',
    red_flags:           row.red_flags ?? '[]',
    improvement_tips:    row.improvement_tips ?? '[]',
    original_text:       row.original_text ?? ''
  }
}];

parameters.text:
=IMPORTANTE: Retorne APENAS JSON puro. Zero texto fora do objeto JSON.

Resume ID: {{ $json.resume_id }}

CONTEXTO DA ANÁLISE:
- Score de empregabilidade: {{ $json.employability_score }}/100
- Red flags identificados: {{ $json.red_flags }}
- Melhorias recomendadas: {{ $json.improvement_tips }}

CURRÍCULO ORIGINAL:
{{ $json.original_text }}

NOVA RESPOSTA DO CANDIDATO:
{{ $json.message }}

INSTRUÇÃO:
Com base na memória acumulada da conversa e na resposta acima:
- Se ainda faltam informações essenciais, retorne: {"done": false, "message": "<próxima pergunta objetiva>"}
- Se já tem informações suficientes para gerar o currículo, retorne o JSON completo com "done": true e "final_resume" preenchido.

parameters.jsCode:
const raw = $input.first().json.output || "";
const body = $('Code - Valida Body').first().json || {};

// Remove <think> do qwen3
const stripped = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

let parsed;
try {
  const match = stripped.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Sem JSON');
  parsed = JSON.parse(match[0]);
} catch (e) {
  return [{ json: { done: false, message: stripped, curriculo: null } }];
}

if (!parsed.done || !parsed.final_resume) {
  return [{ json: { done: false, message: parsed.message || stripped, curriculo: null } }];
}

const c = parsed.final_resume;

return [{
  json: {
    // Para o front
    done:     true,
    message:  null,
    curriculo: c,

    // Para o INSERT no Postgres
    resume_id:       parsed.resume_id || body.resume_id,
    summary:         c.summary        || '',
    experience:      JSON.stringify(c.experience      || []),
    skills:          JSON.stringify(c.skills          || []),
    education:       JSON.stringify(c.education       || []),
    certifications:  JSON.stringify(c.certifications  || []),
    differentials:   c.differentials  || ''
  }
}];

